exercise.solution_code:
#include <iostream>

int g_positives { 0 };
int g_negatives { 0 };

void classify(int value) {
    if (value > 0)
        ++g_positives;
    else if (value < 0)
        ++g_negatives;
}

int main() {
    int v1{}, v2{}, v3{}, v4{}, v5{};
    std::cin >> v1 >> v2 >> v3 >> v4 >> v5;

    classify(v1);
    classify(v2);
    classify(v3);
    classify(v4);
    classify(v5);

    std::cout << "Positives: " << g_positives << '\n';
    std::cout << "Negatives: " << g_negatives << '\n';
    return 0;
}
